const { Storage } = require('@google-cloud/storage');
const path = require('path');

const storage = new Storage();

const ALLOWED_BUCKETS = process.env.ALLOWED_BUCKETS ? process.env.ALLOWED_BUCKETS.split(',') : [];
const MAX_FILE_SIZE = parseInt(process.env.MAX_FILE_SIZE || '104857600'); // 100MB default

function sanitizePath(filePath) {
  if (!filePath) {
    return null;
  }
  
  const normalized = path.normalize(filePath).replace(/^(\.\.(\/|\\|$))+/, '');
  
  if (normalized.includes('..') || normalized.startsWith('/') || normalized.startsWith('\\')) {
    return null;
  }
  
  return normalized;
}

function isValidBucket(bucketName) {
  if (!bucketName || typeof bucketName !== 'string') {
    return false;
  }
  
  if (!/^[a-z0-9][a-z0-9._-]{1,61}[a-z0-9]$/.test(bucketName)) {
    return false;
  }
  
  if (ALLOWED_BUCKETS.length > 0 && !ALLOWED_BUCKETS.includes(bucketName)) {
    return false;
  }
  
  return true;
}

function setSecurityHeaders(res) {
  res.set('X-Content-Type-Options', 'nosniff');
  res.set('X-Frame-Options', 'DENY');
  res.set('X-XSS-Protection', '1; mode=block');
  res.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
}

exports.serveFile = async (req, res) => {
  setSecurityHeaders(res);
  
  if (req.method !== 'GET' && req.method !== 'HEAD') {
    res.status(405).send('Method Not Allowed');
    return;
  }
  
  const bucketName = req.query.bucket;
  const filePath = req.query.path || req.query.file;
  
  if (!bucketName) {
    res.status(400).send('Missing required parameter: bucket');
    return;
  }
  
  if (!filePath) {
    res.status(400).send('Missing required parameter: path or file');
    return;
  }
  
  if (!isValidBucket(bucketName)) {
    res.status(403).send('Invalid or unauthorized bucket');
    return;
  }
  
  const sanitizedPath = sanitizePath(filePath);
  if (!sanitizedPath) {
    res.status(400).send('Invalid file path');
    return;
  }
  
  try {
    const bucket = storage.bucket(bucketName);
    const file = bucket.file(sanitizedPath);
    
    const [exists] = await file.exists();
    if (!exists) {
      res.status(404).send('File not found');
      return;
    }
    
    const [metadata] = await file.getMetadata();
    
    if (metadata.size > MAX_FILE_SIZE) {
      res.status(413).send('File too large');
      return;
    }
    
    const contentType = metadata.contentType || 'application/octet-stream';
    res.set('Content-Type', contentType);
    res.set('Content-Length', metadata.size);
    res.set('Cache-Control', 'public, max-age=3600');
    res.set('ETag', metadata.etag);
    
    const ifNoneMatch = req.get('If-None-Match');
    if (ifNoneMatch && ifNoneMatch === metadata.etag) {
      res.status(304).send();
      return;
    }
    
    if (req.method === 'HEAD') {
      res.status(200).send();
      return;
    }
    
    const readStream = file.createReadStream({
      validation: true
    });
    
    readStream.on('error', (error) => {
      console.error('Stream error:', error);
      if (!res.headersSent) {
        if (error.code === 404) {
          res.status(404).send('File not found');
        } else if (error.code === 403) {
          res.status(403).send('Access denied');
        } else {
          res.status(500).send('Error streaming file');
        }
      } else {
        res.end();
      }
    });
    
    readStream.pipe(res);
    
  } catch (error) {
    console.error('Error serving file:', error);
    
    if (!res.headersSent) {
      if (error.code === 404) {
        res.status(404).send('File not found');
      } else if (error.code === 403) {
        res.status(403).send('Access denied');
      } else if (error.code === 401) {
        res.status(401).send('Unauthorized');
      } else {
        res.status(500).send('Internal server error');
      }
    }
  }
};